def best_matches_in_hadith(query, topn=10):
    scores = []
    for rec in hadith_data:
        text = rec.get('hadithTxt') or rec.get('Matn') or ''
        if not text:
            continue
        sim, parts = robust_similarity(query, text)
        if sim > 0.3:
            scores.append((sim, parts, rec))
    scores.sort(key=lambda x: x[0], reverse=True)
    return scores[:topn]

